import React, { useState } from 'react';
import GlobalStyle from '../styles/GlobalStyle';
import Footer from 'components/footer';
import { TemplateProps } from 'types/layout';
import styled from '@emotion/styled';
import Header from 'components/header';
import theme from '../styles/theme';
import Menu from 'components/menu';
import { useMediaQuery } from 'react-responsive';
import SEO from 'components/SEO';
import type { HeadFC, HeadProps, PageProps } from 'gatsby';

const Layout = function ({ title, description, url, children }: TemplateProps) {
  const isTabletOrMobile = useMediaQuery({ query: '(max-width: 1224px)' });

  const [isMenuOpened, setIsMenuOpened] = useState<boolean>(false);
  const handleClickMenu = () => {
    setIsMenuOpened(!isMenuOpened);
  };

  if (typeof window !== 'undefined') {
    if (isMenuOpened) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'auto';
    }
  }

  return (
    <>
      <GlobalStyle />
      <Container>
        <Gradient1 />
        <Gradient2 />
        <Header onClick={handleClickMenu} />
        {isTabletOrMobile && isMenuOpened && <Menu onClick={handleClickMenu} />}
        {children}
        <Footer />
      </Container>
    </>
  );
};

const Container = styled.div`
  width: 100%;
  padding: 0 56px;
  padding-top: 68px;

  display: flex;
  flex-direction: column;

  @media (max-width: 700px) {
    padding: 20px 0 0 0;
  }
`;

const Gradient1 = styled.div`
  position: fixed;
  width: 1067px;
  height: 1111px;
  left: 0;
  top: 209px;

  background: radial-gradient(
    49.77% 36.47% at 50.72% 45.42%,
    ${theme.main.secondary} 0%,
    rgba(254, 207, 255, 0) 100%
  );
  transform: rotate(-39.57deg);
  z-index: -1;

  @media (max-width: 700px) {
    top: 150px;
  }
`;

const Gradient2 = styled.div`
  position: fixed;
  width: 1087px;
  height: 1111px;
  left: 453px;
  top: -200px;

  background: radial-gradient(
    49.77% 36.47% at 50.72% 45.42%,
    ${theme.main.primary}63 0%,
    rgba(240, 255, 207, 0) 100%
  );
  transform: rotate(24.12deg);
  z-index: -1;

  @media (max-width: 700px) {
    left: 0;
    top: -300px;
  }
`;

export default Layout;
